export default async function(exrArrayBuffer) {

  const exrData = parseExr(exrArrayBuffer, FloatType);

  const { header, width, height, data: linearPixelData, format } = exrData;

  if (format !== 1023) {
    throw new Error('EXR file is not in a supported RGB/RGBA format.');
  }

  const imageData = new ImageData(width, height);
  const outputData = imageData.data;

  const seed = (((width * 73856093) ^ (height * 19349663) ^ 0x9e3779b9) >>> 0);

  for (let y = 0; y < height; y++) {

    const sourceRow = height - 1 - y;

    for (let x = 0; x < width; x++) {

      const destIndex   = (y * width + x) * 4;
      const sourceIndex = (sourceRow * width + x) * 4;

      const linearR = linearPixelData[sourceIndex    ];
      const linearG = linearPixelData[sourceIndex + 1];
      const linearB = linearPixelData[sourceIndex + 2];

      const acescctR = linearToACEScct(linearR);
      const acescctG = linearToACEScct(linearG);
      const acescctB = linearToACEScct(linearB);

      const dR = tpdfDitherNorm(x, y, 0, seed);
      const dG = tpdfDitherNorm(x, y, 1, seed);
      const dB = tpdfDitherNorm(x, y, 2, seed);

      const vR = Math.max(0, Math.min(1, acescctR + dR));
      const vG = Math.max(0, Math.min(1, acescctG + dG));
      const vB = Math.max(0, Math.min(1, acescctB + dB));

      outputData[destIndex    ] = vR * 255;
      outputData[destIndex + 1] = vG * 255;
      outputData[destIndex + 2] = vB * 255;
      outputData[destIndex + 3] =      255;
    }

  }

  return imageData;

}

function uhash(x, y, c, s) {
  let v = (x * 374761393) ^ (y * 668265263) ^ (c * 2246822519) ^ (s * 3266489917);
  v = Math.imul(v ^ (v >>> 15), 2246822519);
  v = Math.imul(v ^ (v >>> 13), 326648991);
  v = (v ^ (v >>> 16)) >>> 0;
  return v / 4294967296;
}

function tpdfDitherNorm(x, y, channel, s) {
  const u1 = uhash(x, y, channel, s);
  const u2 = uhash(x + 0x9e37, y + 0x79b9, channel + 0x517cc1, s ^ 0x85ebca6b);
  return (u1 + u2 - 1) * (1 / 255);
}

function linearToACEScct(x) {
  return x > 0.0078125 ? (Math.log2(x) + 9.72) / 17.52 : 10.5402377416545 * x + 0.0729055341958355;
}